            $excluded = $combos | Where-Object {
                $_.os -eq 'windows-latest' -and $_.version -eq '3.9'
            }
            $excluded | Should -BeNullOrEmpty
        }

        It 'excludes based on partial key match' {
            $config = @{
                os      = @('ubuntu-latest', 'windows-latest', 'macos-latest')
