            $config = @{
                os      = @('ubuntu-latest', 'windows-latest')
                version = @('3.9', '3.10')
                arch    = @('x64', 'arm64')
            }
            $result = New-BuildMatrix -Configuration $config
            $result.matrix.include.Count | Should -Be 8
