            $result.matrix.include.Count | Should -Be 1
            $result.matrix.include[0].Keys.Count | Should -Be 0
        }
    }

    Context 'JSON output' {
        It 'produces valid JSON via ConvertTo-MatrixJson' {
            $config = @{
                os      = @('ubuntu-latest')
                version = @('3.10')
