. ./MatrixGenerator.ps1

# Verify all exported functions have CmdletBinding
foreach (\$fn in @('New-BuildMatrix', 'Get-CartesianProduct', 'Remove-ExcludedCombinations', 'Test-CombinationMatchesRule', 'Add-IncludedCombinations', 'ConvertTo-MatrixJson')) {
    \$cmd = Get-Command \$fn
    \$attr = \$cmd.ScriptBlock.Attributes | Where-Object { \$_ -is [System.Management.Automation.CmdletBindingAttribute] }
    if (\$attr) { Write-Host \"[OK] \$fn has CmdletBinding\" } else { Write-Host \"[FAIL] \$fn missing CmdletBinding\" }

    \$ot = \$cmd.ScriptBlock.Attributes | Where-Object { \$_ -is [System.Management.Automation.OutputTypeAttribute] }
    if (\$ot) { Write-Host \"[OK] \$fn has OutputType: \$(\$ot.Type.Name)\" } else { Write-Host \"[FAIL] \$fn missing OutputType\" }
}
" 2>&1
